#include <stdio.h>

void bubbleSort(int arr[], int n) {
    for (int i = 0; i < n - 1; ++i) {
        for (int j = 0; j < n - i - 1; ++j) {
            if (arr[j] > arr[j + 1]) {
                int tmp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = tmp;
            }
        }
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int arr[1000];
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        bubbleSort(arr, n);
        for (int i = 0; i < n; ++i) {
            printf("%d", arr[i]);
            if (i + 1 < n) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

