        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) arr[i] = sc.nextInt();
            bubbleSort(arr);
            for (int i = 0; i < n; i++) {
                if (i > 0) System.out.print(" ");
                System.out.print(arr[i]);
            }
            System.out.println();
        }
        sc.close();
    }
